THOUGHT: The miscompilation occurs because the pass distributes addition across a trunc with nsw, changing poison behavior. The code only tracks NUW preservation via PreservesNUW and allowsPreservingNUW; it ignores NSW. A fix is to add an analogous NSW preservation check: ensure we don't reassociate through user-chain entries that would strengthen NSW poison, specifically treat trunc as unsafe unless it hasNoSignedWrap when the add/sub is nsw, and propagate a PreservesNSW flag alongside PreservesNUW, gating the transformation. I will implement a conservative check: introduce allowsPreservingNSW mirroring allowsPreservingNUW but for signed wrap, compute PreservesNSW in Extract, and require NSW preservation at the split site.

```bash
applypatch << 'EOF'
*** Begin Patch
*** Update File: llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp
@@
 /// A helper function to check if reassociating through an entry in the user
 /// chain would invalidate the GEP's nuw flag.
 static bool allowsPreservingNUW(const User *U) {
   if (const BinaryOperator *BO = dyn_cast<BinaryOperator>(U)) {
     // Binary operations need to be effectively add nuw.
     auto Opcode = BO->getOpcode();
     if (Opcode == BinaryOperator::Or) {
       // Ors are only considered here if they are disjoint. The addition that
       // they represent in this case is NUW.
       assert(cast<PossiblyDisjointInst>(BO)->isDisjoint());
       return true;
     }
     return Opcode == BinaryOperator::Add && BO->hasNoUnsignedWrap();
   }
   // UserChain can only contain ConstantInt, CastInst, or BinaryOperator.
   // Among the possible CastInsts, only trunc without nuw is a problem: If it
   // is distributed through an add nuw, wrapping may occur:
   // "add nuw trunc(a), trunc(b)" is more poisonous than "trunc(add nuw a, b)"
   if (const TruncInst *TI = dyn_cast<TruncInst>(U))
     return TI->hasNoUnsignedWrap();
   return isa<CastInst>(U) || isa<ConstantInt>(U);
 }

+/// A helper function to check if reassociating through an entry in the user
+/// chain would invalidate the GEP's nsw flag.
+static bool allowsPreservingNSW(const User *U) {
+  if (const BinaryOperator *BO = dyn_cast<BinaryOperator>(U)) {
+    // Binary operations need to be effectively add nsw.
+    auto Opcode = BO->getOpcode();
+    if (Opcode == BinaryOperator::Or) {
+      // Disjoint ORs behave like addition without signed wrap.
+      assert(cast<PossiblyDisjointInst>(BO)->isDisjoint());
+      return true;
+    }
+    return Opcode == BinaryOperator::Add && BO->hasNoSignedWrap();
+  }
+  // Similar to NUW case, trunc without nsw is problematic when distributing
+  // through add nsw: "add nsw trunc(a), trunc(b)" can be more poisonous than
+  // "trunc(add nsw a, b)".
+  if (const TruncInst *TI = dyn_cast<TruncInst>(U))
+    return TI->hasNoSignedWrap();
+  return isa<CastInst>(U) || isa<ConstantInt>(U);
+}
+
 Value *ConstantOffsetExtractor::Extract(Value *Idx, GetElementPtrInst *GEP,
                                         User *&UserChainTail,
-                                        bool &PreservesNUW) {
+                                        bool &PreservesNUW) {
   ConstantOffsetExtractor Extractor(GEP->getIterator());
   // Find a non-zero constant offset first.
   APInt ConstantOffset =
       Extractor.find(Idx, /* SignExtended */ false, /* ZeroExtended */ false,
                      GEP->isInBounds());
   if (ConstantOffset == 0) {
     UserChainTail = nullptr;
     PreservesNUW = true;
     return nullptr;
   }

   PreservesNUW = all_of(Extractor.UserChain, allowsPreservingNUW);

   // Separates the constant offset from the GEP index.
   Value *IdxWithoutConstOffset = Extractor.rebuildWithoutConstOffset();
   UserChainTail = Extractor.UserChain.back();
   return IdxWithoutConstOffset;
 }
@@
 bool SeparateConstOffsetFromGEP::canonicalizeArrayIndicesToIndexSize(
     GetElementPtrInst *GEP) {
*** End Patch
EOF
```

