```bash
sed -n '840,880p' llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp | sed -n '1088,1130p' llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp && sed -i 's/PreservesNUW = all_of(Extractor.UserChain, allowsPreservingNUW);/PreservesNUW = all_of(Extractor.UserChain, allowsPreservingNUW);
  // Do not reassociate through trunc with NSW, as it can strengthen poison.
  for (User *U : Extractor.UserChain) {
    if (auto *TI = dyn_cast<TruncInst>(U)) {
      if (TI->hasNoSignedWrap()) { PreservesNUW = false; break; }
    }
  }/' llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp && sed -n '1088,1130p' llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp && submit-patch
